/* StandardDisplayCategoryConnectCommandRepository.updateConnectList */

    UPDATE PR_STD_CTG_DISP_INFO
    SET    REP_CTG_YN = #{item.repCtgYn}
         , USE_YN     = #{item.useYn}
         , SYS_MOD_ID = COALESCE(#{item.sysModId}, 'admin')
         , SYS_MOD_DTM = NOW()
    WHERE  STD_CTG_NO  = #{item.stdCtgNo}
      AND  DISP_CTG_NO = #{item.dispCtgNo}

/* StandardDisplayCategoryConnectCommandRepository.deleteConnectList */

    UPDATE PR_STD_CTG_DISP_INFO
    SET    DEL_YN      = 'Y'
         , SYS_MOD_ID  = COALESCE(#{item.sysModId}, 'admin')
         , SYS_MOD_DTM = NOW()
    WHERE  STD_CTG_NO  = #{item.stdCtgNo}
      AND  DISP_CTG_NO = #{item.dispCtgNo}
